import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  const initial = (appsmith.model.expected_assets && appsmith.model.expected_assets.length > 0)
    ? appsmith.model.expected_assets
    : [];

  const [rows, setRows] = React.useState(initial);

  React.useEffect(() => {
    appsmith.updateModel({ expected_assets: rows });
  }, [rows]);

  const updateRow = (index, field, value) => {
    const newRows = [...rows];
    newRows[index] = { ...newRows[index], [field]: value };
    setRows(newRows);
  };

  const addRow = () => {
    setRows([...rows, { item: '', qty: 0 }]);
  };

  const removeRow = (index) => {
    setRows(rows.filter((_, i) => i !== index));
  };

  const total = rows.reduce((sum, r) => sum + (parseInt(r.qty) || 0), 0);

  const inpStyle = {
    width: '100%', padding: '7px 10px', border: '0.5px solid #e5e7eb', borderRadius: '6px',
    fontSize: '13px', color: '#111827', background: '#fff', outline: 'none', boxSizing: 'border-box'
  };

  return (
    <div style={{ fontFamily: 'sans-serif' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 80px 32px', gap: '8px', padding: '0 4px 6px', borderBottom: '0.5px solid #e5e7eb', marginBottom: '8px' }}>
        <div style={{ fontSize: '11px', color: '#9ca3af', textTransform: 'uppercase' }}>Item description</div>
        <div style={{ fontSize: '11px', color: '#9ca3af', textTransform: 'uppercase', textAlign: 'center' }}>Qty</div>
        <div></div>
      </div>

      {rows.length === 0 && (
        <div style={{ textAlign: 'center', padding: '20px 0', color: '#9ca3af', fontSize: '13px' }}>
          No items added yet
        </div>
      )}

      {rows.map((row, i) => (
        <div key={i} style={{ display: 'grid', gridTemplateColumns: '1fr 80px 32px', gap: '8px', marginBottom: '6px', alignItems: 'center' }}>
          <input
            style={inpStyle}
            placeholder="e.g. Laptops"
            value={row.item}
            onChange={(e) => updateRow(i, 'item', e.target.value)}
          />
          <input
            style={{ ...inpStyle, textAlign: 'center' }}
            type="number"
            min="0"
            placeholder="0"
            value={row.qty}
            onChange={(e) => updateRow(i, 'qty', parseInt(e.target.value) || 0)}
          />
          <button
            onClick={() => removeRow(i)}
            style={{ width: '32px', height: '32px', border: 'none', background: 'none', cursor: 'pointer', borderRadius: '6px', color: '#9ca3af', fontSize: '16px' }}
          >×</button>
        </div>
      ))}

      <button
        onClick={addRow}
        style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', background: 'none', border: '0.5px dashed #d1d5db', borderRadius: '6px', padding: '7px 14px', fontSize: '13px', color: '#6b7280', cursor: 'pointer', marginTop: '6px', width: '100%' }}
      >+ Add item</button>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '12px', paddingTop: '12px', borderTop: '0.5px solid #e5e7eb', fontSize: '12px', color: '#6b7280' }}>
        <span>Total expected: <strong style={{ color: '#111827' }}>{total}</strong> items</span>
        <span style={{ fontSize: '11px', color: '#9ca3af' }}>Saves with collection record</span>
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
